// Récupération du CSV brut
const csv = $json.data.trim();
const lines = csv.split("\n");

// En-têtes
const headers = lines[0].split(",");
const values = lines[1].split(",");

// Construire un objet {colonne:valeur}
let row = {};
headers.forEach((h, i) => {
  row[h.trim()] = values[i].trim();
});

// Convertir en nombres
const parse = (x) => (x && x !== "N/D") ? parseFloat(x) : null;
const close = parse(row.Close);
const open = parse(row.Open);
const change = (close && open) ? close - open : null;

// Ici tu changes juste symbol + name + currency selon l’indice
return [{
  category: "index",
  symbol: "CAC",             
  name: "CAC 40",               
  currency: "EUR",              
  value: close,
  prev_close: open,
  change_abs: change,
  change_pct: (close && open) ? ((change / open) * 100).toFixed(2) : null,
  timestamp_utc: new Date().toISOString(),
}];

