// XML complet en texte depuis le HTTP Request
const xml = $json.data || '';

// Helper: extrait un taux "1 EUR = rate * CCY" en acceptant ' ou "
function pick(ccy) {
  const re = new RegExp(
    `<Cube\\s+currency=['"]${ccy}['"]\\s+rate=['"]([0-9.]+)['"]`,
    'i'
  );
  const m = xml.match(re);
  return m ? parseFloat(m[1]) : null;
}

// Taux ECB (base EUR)
const EURUSD = pick('USD'); // USD par EUR
const EURJPY = pick('JPY'); // JPY par EUR
const EURGBP = pick('GBP'); // GBP par EUR
const EURCNY = pick('CNY'); // CNY par EUR

const now = new Date().toISOString();
const out = [];

// EURUSD direct
if (EURUSD) {
  out.push({
    category: 'fx',
    symbol: 'EURUSD',
    value: EURUSD,
    timestamp_utc: now,
    source: 'ECB',
    source_url: 'https://www.ecb.europa.eu/stats/eurofxref/',
    confidence: 0.9,
    note: '1 EUR = X USD'
  });
}

// Paires dérivées (base USD)
if (EURJPY && EURUSD) {
  out.push({
    category: 'fx',
    symbol: 'USDJPY',
    value: EURJPY / EURUSD,
    timestamp_utc: now,
    source: 'ECB (derived)',
    source_url: 'https://www.ecb.europa.eu/stats/eurofxref/',
    confidence: 0.85,
    note: '(JPY/EUR)/(USD/EUR)'
  });
}

if (EURGBP && EURUSD) {
  out.push({
    category: 'fx',
    symbol: 'GBPUSD',
    value: EURUSD / EURGBP,
    timestamp_utc: now,
    source: 'ECB (derived)',
    source_url: 'https://www.ecb.europa.eu/stats/eurofxref/',
    confidence: 0.85,
    note: '(USD/EUR)/(GBP/EUR)'
  });
}

if (EURCNY && EURUSD) {
  out.push({
    category: 'fx',
    symbol: 'USDCNY',
    value: EURCNY / EURUSD,
    timestamp_utc: now,
    source: 'ECB (derived)',
    source_url: 'https://www.ecb.europa.eu/stats/eurofxref/',
    confidence: 0.85,
    note: '(CNY/EUR)/(USD/EUR)'
  });
}

// (Optionnel) log rapide si rien n’a matché
if (out.length === 0) {
  // console.log(xml.slice(0, 400)); // décommente pour debug si besoin
}

return out;

