// Commodities wrapper
const incoming = $input.all().map(i => i.json);
const commodities = incoming.flatMap(o =>
  Array.isArray(o?.data) ? o.data : Array.isArray(o) ? o : [o]
);
return [{ json: { commodities } }];

const inputs = $input.all().map(i => i.json);

// concatène si présent
const take = (o,k) => Array.isArray(o?.[k]) ? o[k] : [];
let indices = [], rates = [], fx = [], commodities = [];

for (const o of inputs) {
  indices.push(...take(o,'indices'));
  rates.push(...take(o,'rates'));
  fx.push(...take(o,'fx'));
  commodities.push(...take(o,'commodities'));
}

// aplatit cas indices = [{data:[...]}]
if (indices.length && indices.every(x => x && Array.isArray(x.data))) {
  indices = indices.flatMap(x => x.data);
}

// borne
indices = indices.slice(0, 24);
rates = rates.slice(0, 12);
fx = fx.slice(0, 12);
commodities = commodities.slice(0, 12);

// 🔎 debug (supprime après validation)
const debug = {
  sizes: {
    indices: indices.length,
    rates: rates.length,
    fx: fx.length,
    commodities: commodities.length
  },
  sampleFx: fx[0] || null,
  sampleCommo: commodities[0] || null
};

return [{ json: { indices, rates, fx, commodities, _debug: debug } }];

const obs = ($json.observations || []).filter(o => o.value !== '.');
const last = obs.at(-1), prev = obs.at(-2);
const v = last ? Number(last.value) : null;
const p = prev ? Number(prev.value) : null;
return [{
  category: "macro",
  metric: "inflation_yoy",
  country: "US",
  symbol: "US_CPI_YoY",
  name: "US CPI YoY",
  period: last?.date || null,
  unit: "%YoY",
  value: v,
  prev_value: p,
  change_abs: (v!=null&&p!=null)? Number((v-p).toFixed(2)) : null,
  change_pct: (v!=null&&p)? Number((((v-p)/p)*100).toFixed(2)) : null,
  timestamp_utc: new Date().toISOString(),
}];

