}];

const obs = ($json.observations || []).filter(o => o.value !== '.');
const last = obs.at(-1), prev = obs.at(-2);
const v = last ? Number(last.value) : null;
const p = prev ? Number(prev.value) : null;

return [{
  category: "macro",
  metric: $json.realtime_start ? "unemployment_rate" : "inflation_yoy", // indicatif
  country: "FR",
  symbol: $json.realtime_start ? "FR_UNRATE" : "FR_CPI_YoY",
  name: $json.realtime_start ? "France Unemployment Rate (Harmonised)" : "France CPI YoY",
  period: last?.date || null,
  unit: $json.realtime_start ? "%" : "%YoY",
  value: v,
  prev_value: p,
  change_abs: (v!=null&&p!=null) ? Number((v-p).toFixed(2)) : null,
  change_pct: (v!=null&&p) ? Number(((v-p)/p*100).toFixed(2)) : null,
  timestamp_utc: new Date().toISOString(),
}];

const macro = $json.macro || [];
const now = new Date();
const iso = now.toISOString().slice(0,10);
const rfc = now.toUTCString();

const rss = `<?xml version="1.0" encoding="UTF-8"?>
<rss version="2.0" xmlns:content="http://purl.org/rss/1.0/modules/content/">
  <channel>
    <title>Morning Meeting – Macro (US & FR)</title>
    <link>https://example.com/morning-meeting</link>
    <description>Inflation & chômage – US et France</description>
    <language>fr-fr</language>
    <lastBuildDate>${rfc}</lastBuildDate>
    <item>
      <title>Macro - ${iso}</title>
      <guid>macro-${Date.now()}</guid>
      <pubDate>${rfc}</pubDate>
      <content:encoded><![CDATA[
${JSON.stringify(macro, null, 2)}
      ]]></content:encoded>
      <source url="https://fred.stlouisfed.org/">FRED (OECD/Eurostat)</source>
    </item>
  </channel>
</rss>`;

return [{ json: { rss } }];

// Input attendu: { indices:[], rates:[], fx:[], commodities:[], _debug? }
const j = $json;

const num = v => (typeof v==="number" ? v : Number(String(v ?? "").replace(",", ".")));
const pct = v => Number.isFinite(v) ? (v>=0?`+${v.toFixed(2)}%`:`${v.toFixed(2)}%`) : "—";
const lvl = (v,d=2)=> Number.isFinite(v) ? v.toFixed(d) : "—";
const arr = a => Array.isArray(a) ? a : [];
const abs = Math.abs;

// ---- helpers alias-tolérants
const findIndex = (...aliases) => {
  const A = aliases.map(s=>s.toUpperCase());
  return arr(j.indices).find(x => {
    const sym = String(x.symbol||"").toUpperCase();
    const name= String(x.name||"").toUpperCase();
    return A.some(a => sym===a || name.includes(a));
  });
};
const findFx   = (...aliases) => {
  const A = aliases.map(s=>s.toUpperCase().replace("/",""));
  return arr(j.fx).find(x => A.includes(String(x.symbol||"").toUpperCase()));
};
const findCom  = (...aliases) => {
  const A = aliases.map(s=>s.toUpperCase());
  return arr(j.commodities).find(x => {
    const s = String(x.symbol||"").toUpperCase();
    const n = String(x.name||"").toUpperCase();
    return A.some(a => s.includes(a) || n.includes(a));
  });
};

// ---- incontournables (forcés si présents)
const CAC    = findIndex("CAC","CAC 40","PX1");
const SPX    = findIndex("SPX","S&P 500","SP 500");
const EURUSD = findFx("EURUSD","EUR/USD");
const WTI    = findCom("WTI");
const GOLD   = findCom("XAUUSD","GOLD","XAU");

// ---- movers indices |Δ%| ≥ 0.8 (hors CAC/SPX)
const movers = arr(j.indices)
  .filter(x => !["CAC","SPX"].includes(String(x.symbol||"").toUpperCase()))
  .map(x => ({...x, _ch: num(x.change_pct ?? x.pct ?? x.changePercent)}))
  .filter(x => Number.isFinite(x._ch) && abs(x._ch) >= 0.8)
  .sort((a,b)=>abs(b._ch)-abs(a._ch))
  .slice(0,2);

// ---- taux (Δ ≥ 4 bps OU US > 4%)
const selRates = arr(j.rates).filter(x=>{
  const ch = num(x.change_abs);
  const v  = num(x.value);
  const isUS = String(x.symbol||"").toUpperCase().includes("US");
  return (abs(ch) >= 0.04) || (isUS && v > 4);
}).slice(0,2);

// ---- FX additionnels
const fxAdd = arr(j.fx).filter(x=>{
  const sym = String(x.symbol||"").toUpperCase();
  const ch  = num(x.change_pct);
  const v   = num(x.value);
  // Règles: USDJPY si |Δ|>=0.5% OU "niveau rond" ~150; tu peux étendre à GBPUSD/USDCNY si tu veux
  if (sym === "USDJPY") {
