// ---- Helpers robustes
function strip(s=''){ return s.replace(/<[^>]*>/g,' ').replace(/&nbsp;/g,' ').replace(/\s+/g,' ').trim(); }
function numEU(s){
  if (s == null) return null;
  let t = String(s).replace(/[^\d.,\-]/g,'').trim();
  // "," et "." présents → on suppose ","=milliers, "."=décimal (ex: 2,139.00)
  if (t.includes(',') && t.includes('.')) {
    t = t.replace(/,/g, '');
  } else if (t.includes(',')) {
    // sinon "," = décimal (ex: 40,59)
    t = t.replace(/,/g, '.');
