// normalise nombres et calcule changePct si absent (à partir de price & change)
function normalize(r) {
  const price  = Number(r.price);
  const change = Number(r.change);
  let changePct = (r.changePct !== undefined) ? Number(r.changePct) : undefined;

  if (!Number.isFinite(changePct)) {
    const prev = (Number.isFinite(price) && Number.isFinite(change)) ? (price - change) : undefined;
    changePct = (Number.isFinite(prev) && prev !== 0) ? (change / prev * 100) : undefined;
  }
  return { ...r, price, change, changePct };
}

