const LIMIT = 3;

/* --------- helpers --------- */
function asNum(v){
  if (typeof v === 'number') return v;
  if (v == null) return NaN;
  const s = String(v).trim().replace(/[%\s]/g,'').replace(',', '.');
  const m = s.match(/-?\d+(\.\d+)?/);
  return m ? Number(m[0]) : NaN;
}

function pctFromRaw(r){
  const direct = asNum(r.change_pct ?? r.percent_change ?? r.changePercent);
  if (Number.isFinite(direct)) return direct;
  const abs  = asNum(r.change_abs ?? r.change ?? r.delta ?? r.chg);
  const prev = asNum(r.prev_close ?? r.prevClose ?? r.previous);
  const last = asNum(r.value ?? r.price ?? r.last);
  const denom = Number.isFinite(prev) ? prev : (Number.isFinite(last) ? last - abs : NaN);
  if (Number.isFinite(abs) && Number.isFinite(denom) && denom !== 0) return (abs/denom)*100;
  return NaN;
}

function looksNormalized(o){
  return o && typeof o === 'object' && 'changePct' in o && Number.isFinite(asNum(o.changePct));
}
function looksRaw(o){
  return o && typeof o === 'object' && (
    'change_pct' in o || 'prev_close' in o || 'change_abs' in o
  );
}

function walkArrays(node, out = []){
  if (Array.isArray(node)){
    if (node.length && typeof node[0] === 'object') out.push(node);
    for (const el of node) walkArrays(el, out);
  } else if (node && typeof node === 'object'){
    for (const v of Object.values(node)) walkArrays(v, out);
  }
  return out;
}

function symFromAny(r){
  let s = r.symbol ?? r.raw_symbol ?? r.ticker ?? '';
  if (!s) {
    const u = r.url ?? r.href ?? r.link ?? r.path;
    if (u) {
      const m = String(u).match(/\/symbol\/([A-Za-z0-9.\-]+)/);
      if (m) s = m[1];
    }
  }
  return (s || '').toString().trim().toUpperCase();
}

function cleanName(n){
  if (!n) return '';
  return String(n).replace(/\s+/g,' ').replace(/\u00a0/g,' ').trim();
}

function bestNameFromRecord(r){
  const candidates = [
    r.name, r.company, r.companyName, r.longName, r.securityName,
    r.instrumentName, r.displayName, r.company_full, r.company_full_name, r.Company
  ].map(cleanName).filter(Boolean);
  // garder la plus longue chaîne non égale au symbole (évite "AAPL" comme nom)
  return (sym) => candidates
    .filter(x => x.toUpperCase() !== sym)
    .sort((a,b) => b.length - a.length)[0] || '';
}

/* --------- 1) collecter toutes les listes --------- */
const allArrays = [];
for (const it of items) walkArrays(it.json ?? it, allArrays);

/* --------- 2) Construire un dictionnaire symbole -> nom complet --------- */
const symToFullName = new Map();
for (const arr of allArrays){
  if (!arr.length || typeof arr[0] !== 'object') continue;
  for (const r of arr){
    const sym = symFromAny(r);
    if (!sym) continue;
    const pick = bestNameFromRecord(r)(sym);
    if (!pick) continue;
    const current = symToFullName.get(sym) || '';
    // on garde le nom le plus long (souvent "Alphabet Inc. (Class A)" vs "Alphabet")
    if (pick.length > current.length) symToFullName.set(sym, pick);
  }
}

/* --------- 3) Normaliser toutes les lignes avec nom enrichi --------- */
const rows = [];
for (const arr of allArrays){
  if (!arr.length || typeof arr[0] !== 'object') continue;

  if (looksNormalized(arr[0])) {
    for (const r of arr){
      const cp = asNum(r.changePct);
      if (!Number.isFinite(cp)) continue;
      const sym = symFromAny(r);
      let nm = bestNameFromRecord(r)(sym) || symToFullName.get(sym) || r.name || r.company || sym;
      nm = cleanName(nm);
      rows.push({
        source: r.index ?? r.list ?? 'norm',
        symbol: sym,
        name: nm,
        changePct: Number(cp.toFixed(2))
      });
    }
  } else if (looksRaw(arr[0])) {
    for (const r of arr){
      const cp = pctFromRaw(r);
      if (!Number.isFinite(cp)) continue;
      const sym = symFromAny(r);
      let nm = bestNameFromRecord(r)(sym) || symToFullName.get(sym) || r.name || r.company || sym;
      nm = cleanName(nm);
      rows.push({
        source: r.exchange_mic ?? r.market ?? r.list ?? 'raw',
        symbol: sym,
        name: nm,
        changePct: Number(cp.toFixed(2))
      });
    }
  }
}

/* --------- 4) Dédoublonnage & TOPS --------- */
const bySym = new Map();
for (const r of rows){
  const key = r.symbol || r.name;
  if (!key) continue;
  const cur = bySym.get(key);
  if (!cur || Math.abs(r.changePct) > Math.abs(cur.changePct)) bySym.set(key, r);
}
const merged = [...bySym.values()];

const winners = merged.filter(x => x.changePct > 0)
