function getSector(company, symbol) {
  // Essaie par symbole d'abord
  const sym = (symbol || '').replace(/\..+$/, '').toUpperCase();
  if (SECTORS[sym]) return SECTORS[sym];

  // Essaie par nom
  const name = (company || '').toUpperCase();
  for (const [key, sector] of Object.entries(SECTORS)) {
    if (name.includes(key)) return sector;
  }

  // Détection par mots-clés dans le nom
  if (name.includes('BANK') || name.includes('BANQUE')) return 'Banque';
  if (name.includes('ENERGY') || name.includes('PETRO') || name.includes('OIL')) return 'Énergie';
  if (name.includes('TECH') || name.includes('SOFTWARE')) return 'Tech';
  if (name.includes('PHARMA') || name.includes('HEALTH')) return 'Santé';

  return 'Industrie'; // Fallback générique
}

