}
function fmtPct(v){
  const n = Number(v);
  if (!Number.isFinite(n)) return '';
  const sign = n >= 0 ? '+' : '';
  return `(${sign}${n.toFixed(2).replace('.', ',')}%)`;
}
function fmtFx(v){
