// 2) Helpers
function toISO(ev){
  const cands = [ev.date, ev.datetime, ev.utcTime, ev.timestamp];
  for (const c of cands){
    if (!c) continue;
    const d = new Date(c);
    if (!isNaN(d)) return d.toISOString();
  }
  if (ev.date && ev.time){
    const d2 = new Date(`${ev.date} ${ev.time} UTC`);
    if (!isNaN(d2)) return d2.toISOString();
  }
  return null;
}
function timeLocal(iso){
  const d = new Date(iso);
  return isNaN(d)
    ? ''
    : d.toLocaleString('fr-FR', { timeZone: TZ, hour: '2-digit', minute: '2-digit' });
}
function isMH(impactRaw, title){
  const s = String(impactRaw||'').toLowerCase();
  if (/\bhigh\b|haute|élev|elev|3\s*bull|strong/i.test(s)) return 'high';
  if (/\bmedium\b|moyen|2\s*bull|moderate/i.test(s)) return 'medium';
  const t = String(title||'').toLowerCase();
  if (/(cpi|hicp|inflation|nfp|payroll|emploi|unemployment|pmi|ism|retail\s*sales|gdp|rate\s*decision|fomc|ecb|boe|boj)/i.test(t)) return 'medium';
  return '';
}
const EXCLUDE = /(holiday|bank\s*holiday|jour\s*férié|tentative|tba|all\s*day|daylight\s*saving|dst)/i;
const EU_TITLE = /(france|french|euro\s*area|zone\s*euro|eurozone|german|allemagne|spain|espagne|italy|italie)/i;

// Utilitaires de date en TZ Paris
function dateParisYYYYMMDD(d){
  // Renvoie 'YYYY-MM-DD' dans le fuseau TZ
  return d.toLocaleDateString('en-CA', { timeZone: TZ });
}
function isoToParisYYYYMMDD(iso){
  const d = new Date(iso);
  if (isNaN(d)) return '';
  return dateParisYYYYMMDD(d);
}

// 3) Normalisation (Medium/High uniquement)
let norm = items.map(e=>{
  const iso = toISO(e);
  if (!iso) return null;
  const title = String(e.title||'').trim();
  if (EXCLUDE.test(title)) return null;

  const mh = isMH(e.impact || e.impactText || e.impact_desc, title);
  if (!mh) return null; // on garde seulement Medium/High

  const d = new Date(iso);
  if (isNaN(d)) return null;

  return {
    section: 'calendar',
    event: title,
    country: String(e.country||'').toUpperCase(),
    importance: mh,
    importance_score: mh==='high' ? 3 : 2,
    previous: e.previous ?? null,
    forecast: e.forecast ?? null,
    actual: e.actual ?? null,
    date_iso: iso,
    time_local: timeLocal(iso),
    ymd_paris: isoToParisYYYYMMDD(iso),
  };
}).filter(Boolean);

// 4) Filtre : uniquement les événements D'AUJOURD'HUI (heure Paris)
