  const title = normTitle(titles[i])
    .replace(/\s+/g, ' ')
    .replace(/(?:\bAOF\b|\bBoursier\b|\bAFP\b|\bEuroland\s+Corporate\b)/gi, '')
    .trim();

  out.push({ json: { title: title || 'Article', url: href } });
}

return out;

// Extraction texte + published_at (robuste)
// Attend en entrée (après merge par clé 'url') : { title, url, body|data|binary }
// Retourne : { title, url, text, published_at }

const TZ = 'Europe/Paris';

function getHtml(item){
  // Plusieurs emplacements possibles selon le HTTP node
  if (typeof item.json?.data === 'string') return item.json.data;
  if (typeof item.json?.body === 'string') return item.json.body;
  if (item.binary?.data?.data){
    try { return Buffer.from(item.binary.data.data, 'base64').toString('utf-8'); } catch(e){}
  }
  return '';
}

function pickContent(html){
  // 1) <article>…</article>
  let m = html.match(/<article[^>]*>([\s\S]*?)<\/article>/i);
  if (m) return m[1];

  // 2) <main>…</main>
  m = html.match(/<main[^>]*>([\s\S]*?)<\/main>/i);
  if (m) return m[1];

  // 3) blocs usuels
  m = html.match(/<(div|section)[^>]*?(id|class)\s*=\s*["'][^"']*(article-body|post-content|entry-content|content|body|texte)["'][^>]*>([\s\S]*?)<\/\1>/i);
  if (m) return m[4];

  // 4) fallback : tout le HTML
  return html;
}

function stripBoilerplate(txt){
  // Enlève scripts/styles/menus/footers
  return txt
    .replace(/<script[^>]*>[\s\S]*?<\/script>/gi, '')
    .replace(/<style[^>]*>[\s\S]*?<\/style>/gi, '')
    .replace(/<(header|footer|nav|aside)[^>]*>[\s\S]*?<\/\1>/gi, '')
    .replace(/<!--[\s\S]*?-->/g, '')
    .replace(/<[^>]+>/g, ' ')
    .replace(/\s+/g, ' ')
    .replace(/\s{2,}/g, ' ')
    // boilerplate courant
    .replace(/(S'abonner|Abonnez-vous|Suivez[- ]nous|Mentions légales|Cookies|Newsletter)/gi, ' ')
    .trim();
}

function extractPublishedAt(html){
  // Plusieurs métas possibles sur les sites d'actu
  let m =
    html.match(/<meta[^>]+property=["']article:published_time["'][^>]+content=["']([^"']+)["']/i) ||
    html.match(/<meta[^>]+name=["']pubdate["'][^>]+content=["']([^"']+)["']/i) ||
    html.match(/<meta[^>]+name=["']date["'][^>]+content=["']([^"']+)["']/i) ||
    html.match(/<time[^>]+datetime=["']([^"']+)["']/i);
  if (m) {
    const d = new Date(m[1]);
    if (!isNaN(d)) return d.toISOString();
  }
  return null;
}

const out = [];
for (const item of $input.all()){
  const title = String(item.json?.title ?? '').trim();
  // URL peut venir du flux titres (merge) ; sinon essaie de la récupérer côté http fullResponse si dispo
  const url = String(item.json?.url ?? item.json?.requestUrl ?? item.json?.request?.url ?? '').trim();
  const status = Number(item.json?.statusCode ?? 200);
  const html = getHtml(item);

  if (!title || !url || !html || html.length < 100){
    out.push({ json: { title, url, text: null, published_at: null, error: 'No HTML body' }});
    continue;
  }
  if (status === 503){
    out.push({ json: { title, url, text: null, published_at: null, error: 'HTTP 503' }});
    continue;
  }

  const core = pickContent(html);
  let text = stripBoilerplate(core);

  // petite sécurité langue FR (optionnelle, simple heuristique)
  const isFrench = / le | la | les | des | une | un | et | ou | pour | selon | marché /i.test(text);
  if (!isFrench && text.length > 0){
    // on laisse passer, mais tu peux filtrer ici si tu veux strict FR
  }

  // limite pour le LLM
  if (text.length > 2000) text = text.slice(0, 2000);

  const published_at = extractPublishedAt(html);

  out.push({
    json: {
      title,
      url,
      text,
      published_at
    }
  });
}

return out;

const TZ = 'Europe/Paris';
const MAX_ITEMS = 3;

function normalize(s){
  return String(s || '').normalize('NFD').replace(/[\u0300-\u036f]/g, '').toLowerCase();
}

function escRe(s){ 
  return String(s).replace(/[.*+?^${}()|[\]\\]/g, '\\$&'); 
}

function kwHit(normText, kw){
  const k = normalize(kw);
  if (!k) return false;
  try {
    const isAlphaNum = /^[a-z0-9\s]+$/i.test(k);
    const pat = isAlphaNum ? new RegExp(`\\b${escRe(k)}\\b`, 'i') : new RegExp(escRe(k), 'i');
    return pat.test(normText);
  } catch(e) {
    return normText.includes(k);
  }
}

