  for (const o of all){
    if (o && o.tag === tag) {
      console.log('Tag trouvé:', tag);
      return o;
    }
  }
  return null;
}

const macro = findByTag('macro_bundle') || {};
const cal   = findByTag('calendar_bundle') || {};

// Fallback si macro est vide mais qu'on a des données directes
if (!macro.macro_headlines && all.length > 0) {
  console.log('⚠️ macro_bundle vide, recherche alternative...');
  const alt = all.find(x => Array.isArray(x?.macro_headlines));
  if (alt) {
    console.log('✅ Données macro trouvées sans tag');
    Object.assign(macro, alt);
  }
}

console.log('Macro headlines:', macro.macro_headlines?.length || 0);
console.log('Macro themes:', macro.macro_themes?.length || 0);
console.log('Macro snippets:', macro.macro_snippets?.length || 0);
console.log('Calendar line:', cal.calendar_line || '(vide)');
console.log('=== DEBUG JS2 END ===');

return [{
  json: {
    macro_headlines: Array.isArray(macro.macro_headlines) ? macro.macro_headlines : [],
    macro_themes: Array.isArray(macro.macro_themes) ? macro.macro_themes : [],
    macro_snippets: Array.isArray(macro.macro_snippets) && macro.macro_snippets.length > 0 
      ? macro.macro_snippets 
      : [all.find(x => x.text)?.text || ''], // Fallback sur le texte brut
    calendar_line: cal.calendar_line || 'Pas de publication majeure aujourd\'hui.'
  }
}];

