/**
 * Input: aucun obligatoire si tu utilises PULL par nom de nœud.
 * Output: { subject, html }
 *
 * À adapter si tes nœuds ont d'autres noms.
 */
const PULL = {
  market: 'SyntheseMarches',   // nœud qui renvoie { paragraph, bullets[] }
  topflop: 'TopFlopFinal',     // nœud qui renvoie { gainer:{...}, loser:{...} } OU { top_du_jour:{...}, flop_du_jour:{...} }
  briefing: 'BriefsLLM'        // (optionnel) nœud qui renvoie { content: "long texte" } ou { text }
};

// ---- helpers
const getFromNode = (name) => {
  try { return $items(name, 0, 0).json || null; } catch { return null; }
};
const esc = (s='') => String(s)
  .replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;')
  .replace(/"/g,'&quot;').replace(/'/g,'&#39;');

const fmtDate = new Date().toLocaleDateString('fr-FR',{ weekday:'long', year:'numeric', month:'long', day:'numeric' });

// ---- 1) Récupération des données (marché / top-flop / briefing)
const marketRaw = getFromNode(PULL.market) || $json.market || $json;
const topflopRaw = getFromNode(PULL.topflop) || $json.topflop || $json;
const briefingRaw = getFromNode(PULL.briefing) || $json.briefing || $json;

// Normalise marché
const market = {
  paragraph: marketRaw?.paragraph || '',
  bullets: Array.isArray(marketRaw?.bullets) ? marketRaw.bullets : []
};

// Normalise top/flop (gère les deux formats)
function normTF(tf){
  // nouveau format attendu { gainer:{name,symbol,change,title,intro,catalysts[]}, loser:{...} }
  if (tf?.gainer || tf?.loser){
    const pack = (x) => x ? {
      name: x.name || x.entreprise || x.company || '',
      symbol: x.symbol || x.ticker || '',
      change: x.change || x.variation || '',
      title: x.title || (x.name ? `${x.name} (${x.symbol||''}) — ${x.change||''}` : ''),
      sector: x.sector || x.secteur || '',
      intro: x.intro || x.raisons_probables || 'Non disponible',
      catalysts: Array.isArray(x.catalysts) && x.catalysts.length ? x.catalysts
                : (x.raisons_probables ? [x.raisons_probables] : ['Non disponible'])
    } : null;
    return { gainer: pack(tf.gainer), loser: pack(tf.loser),
             top_of_week: tf.top_of_week || tf.top_de_la_semaine || null,
             flop_of_week: tf.flop_of_week || tf.flop_de_la_semaine || null };
  }
  // ancien format { top_du_jour:{entreprise,variation,secteur,raisons_probables}, flop_du_jour:{...} }
  if (tf?.top_du_jour || tf?.flop_du_jour){
    const packOld = (x) => x ? ({
      name: x.entreprise || '',
      symbol: x.symbol || '',
      change: x.variation || '',
      title: x.entreprise ? `${x.entreprise}${x.symbol?` (${x.symbol})`:''} — ${x.variation||''}` : '',
      sector: x.secteur || '',
      intro: x.raisons_probables || 'Non disponible',
      catalysts: x.raisons_probables ? [x.raisons_probables] : ['Non disponible']
    }) : null;
    return { gainer: packOld(tf.top_du_jour), loser: packOld(tf.flop_du_jour),
             top_of_week: tf.top_de_la_semaine || null,
             flop_of_week: tf.flop_de_la_semaine || null };
  }
  return { gainer:null, loser:null };
}
const tf = normTF(topflopRaw);

// Normalise briefing (texte libre optionnel)
const briefingText =
  briefingRaw?.content?.text || briefingRaw?.content || briefingRaw?.text || '';

const sectionBriefing = briefingText
  ? `<section class="card">
       <h2>Briefing</h2>
       ${esc(String(briefingText)).split(/\n{2,}/).map(p=>`<p>${p.replace(/\n/g,'<br>')}</p>`).join('')}
     </section>`
  : '';

// ---- 2) HTML
const css = `
  :root{
    --bg:#0b0c10; --cards:#12141a; --muted:#98a2b3; --txt:#e6e8ee;
    --accent:#4f46e5; --up:#10b981; --down:#ef4444; --chip:#1f2430;
  }
  *{box-sizing:border-box}
  body{margin:0;padding:32px;background:var(--bg);color:var(--txt);font:14px/1.6 system-ui,-apple-system,Segoe UI,Roboto,Ubuntu,Cantarell,'Helvetica Neue',Arial}
  .wrap{max-width:860px;margin:0 auto}
  .header{display:flex;justify-content:space-between;align-items:end;margin-bottom:20px}
  .brand{font-weight:700;font-size:20px}
  .date{color:var(--muted)}
  .card{background:var(--cards);border:1px solid #1f2430;border-radius:16px;padding:20px;margin:14px 0;box-shadow:0 1px 0 rgba(255,255,255,.04) inset}
  h1,h2{margin:0 0 12px 0}
  h1{font-size:22px} h2{font-size:16px;color:#cbd5e1}
  ul{margin:8px 0 0 18px} li{margin:6px 0}
  .grid{display:grid;gap:14px}
  @media(min-width:700px){ .grid.two{grid-template-columns:1fr 1fr} }
  .badge{display:inline-block;padding:2px 8px;border-radius:999px;background:var(--chip);color:var(--muted);font-size:12px;margin-left:6px}
  .pill{padding:2px 8px;border-radius:999px;font-weight:600}
  .pill.up{background:rgba(16,185,129,.12);color:var(--up)}
  .pill.down{background:rgba(239,68,68,.12);color:var(--down)}
  .title{display:flex;align-items:center;gap:8px;flex-wrap:wrap}
  .muted{color:var(--muted)}
  .sources{font-size:12px;color:var(--muted)}
`;

const topCard = (side, data) => {
  if (!data) return '';
  const dir = (data.change||'').trim().startsWith('-') ? 'down' : 'up';
  return `
  <section class="card">
    <div class="title">
      <h2>${side}</h2>
      ${data.sector ? `<span class="badge">${esc(data.sector)}</span>`:''}
      ${data.symbol ? `<span class="badge">${esc(data.symbol)}</span>`:''}
      ${data.change ? `<span class="pill ${dir}">${esc(data.change)}</span>`:''}
    </div>
    ${data.title ? `<p class="muted">${esc(data.title)}</p>`:''}
    ${data.intro ? `<p>${esc(data.intro)}</p>`:''}
    ${Array.isArray(data.catalysts) && data.catalysts.length
      ? `<div class="sources"><strong>Catalyseurs</strong><ul>${
           data.catalysts.map(c=>`<li>${esc(c)}</li>`).join('')
         }</ul></div>` : ''
    }
  </section>`;
};

const marketHTML = `
<section class="card">
  <h2>Synthèse marchés</h2>
  ${market.paragraph ? `<p>${esc(market.paragraph)}</p>`:''}
  ${market.bullets.length ? `<ul>${market.bullets.map(b=>`<li>${esc(b)}</li>`).join('')}</ul>`:''}
</section>`;

const weekly = (tf.top_of_week || tf.flop_of_week)
  ? `<section class="card">
       <h2>Top / Flop de la semaine</h2>
       <p>${tf.top_of_week ? `Top : ${esc(tf.top_of_week)}`:''}
          ${tf.flop_of_week ? `<br>Flop : ${esc(tf.flop_of_week)}`:''}</p>
     </section>` : '';

const html = `
<!doctype html>
<html lang="fr">
<meta charset="utf-8">
<meta name="viewport" content="width=device-width,initial-scale=1">
<title>Morning – ${fmtDate}</title>
<style>${css}</style>
<body>
  <div class="wrap">
    <header class="header">
      <div class="brand">Morning Meeting</div>
      <div class="date">${esc(fmtDate)}</div>
    </header>

    ${marketHTML}

    <div class="grid two">
      ${topCard('Top du jour', tf.gainer)}
      ${topCard('Flop du jour', tf.loser)}
    </div>

    ${weekly}
    ${sectionBriefing}
  </div>
</body>
</html>`;

// Sujet d’email pratique
const subject = `Morning – ${fmtDate}`;

return [{ json: { subject, html } }];
